})

import type { Breakpoint, ResponsiveObject, System } from "@yamada-ui/react"
import { useMemo } from "react"
import { useSystem } from "@yamada-ui/react"
import { useBreakpoint } from "./use-breakpoint"

/**
 * `useBreakpointValue` is a custom hook that returns the value of the current breakpoint from the provided object.
 * This hook monitors changes in the window size and returns the appropriate value.
 *
 * @see https://yamada-ui.com/docs/hooks/use-breakpoint-value
 */
export const useBreakpointValue = <Y>(
  values: ResponsiveObject<Y, false>,
): Y => {
  const system = useSystem()
  const breakpoint = useBreakpoint()

  return useMemo(
    () => getBreakpointValue<Y>(values)(system, breakpoint),
    [values, system, breakpoint],
  )
}

export const getBreakpointValue =
  <Y>(values: ResponsiveObject<Y, false> = {}) =>
  (system: System, breakpoint: Breakpoint): Y => {
    const breakpoints = system.breakpoints.keys

    if (!breakpoints.length) {
      console.warn("getBreakpointValue: `breakpoints` is undefined.")
    }

    const currentIndex = breakpoints.indexOf(breakpoint)

    for (let i = currentIndex; 0 < i; i--) {
      const nextBreakpoint = breakpoints[i]

      if (nextBreakpoint && values.hasOwnProperty(nextBreakpoint)) {
        return values[nextBreakpoint] as Y
      }
    }

    return values.base as Y
  }

import type { FC } from "react"
import type { ThemeConfig } from "@yamada-ui/react"
import { page, render } from "#test/browser"
import { styled, config as defaultConfig } from "@yamada-ui/react"
import { UIProvider } from "../../providers/ui-provider"
import { useBreakpoint } from "./use-breakpoint"

describe("useBreakpoint", () => {
  test("updates breakpoint when viewport changes", async () => {
    await page.viewport(1500, 800)

    const Component: FC = () => {
      const breakpoint = useBreakpoint()

      return <styled.p data-testid="bp">{breakpoint}</styled.p>
    }

    await render(<Component />)

    await expect.element(page.getByTestId("bp")).toHaveTextContent("base")

    await page.viewport(600, 800)

    await expect.element(page.getByTestId("bp")).toHaveTextContent("md")
  })

  test("renders correctly with direction up", async () => {
    const defaultResizeObserver = window.ResizeObserver

    window.ResizeObserver = class ResizeObserver {
      constructor(cb: ResizeObserverCallback) {
        ;(() => {
          cb(
            [
              {
                contentRect: {
                  height: 0,
                  width: 500,
                },
              },
            ] as ResizeObserverEntry[],
            this,
          )
        })()
      }
      observe = vi.fn()
      unobserve = vi.fn()
      disconnect = vi.fn()
    }

    const containerRef = { current: document.createElement("div") }
    const config: ThemeConfig = {
      ...defaultConfig,
      breakpoint: {
        containerRef,
        direction: "up",
        identifier: "@container",
      },
    }

    const Component: FC = () => {
      const breakpoint = useBreakpoint()

      return <styled.p data-testid="bp">{breakpoint}</styled.p>
    }

    await render(
      <UIProvider config={config}>
        <Component />
      </UIProvider>,
      { withProvider: false },
    )

    await expect.element(page.getByTestId("bp")).toBeInTheDocument()

    window.ResizeObserver = defaultResizeObserver
  })

  test("renders the expected breakpoint for container width with default direction", async () => {
    const defaultResizeObserver = window.ResizeObserver

    window.ResizeObserver = class ResizeObserver {
      constructor(cb: ResizeObserverCallback) {
        ;(() => {
          cb(
            [
              {
                contentRect: {
                  height: 0,
                  width: 1200,
                },
              },
            ] as ResizeObserverEntry[],
            this,
          )
        })()
      }
      observe = vi.fn()
      unobserve = vi.fn()
      disconnect = vi.fn()
    }

    const containerRef = { current: document.createElement("div") }
    const config: ThemeConfig = {
      ...defaultConfig,
      breakpoint: {
        containerRef,
        identifier: "@container",
      },
    }

    const Component: FC = () => {
      const breakpoint = useBreakpoint()

      return <styled.p data-testid="bp">{breakpoint}</styled.p>
    }

    await render(
      <UIProvider config={config}>
        <Component />
      </UIProvider>,
      { withProvider: false },
    )

    await expect.element(page.getByTestId("bp")).toHaveTextContent("xl")

    window.ResizeObserver = defaultResizeObserver
  })

  test("observes container and calls disconnect on cleanup", async () => {
    const defaultResizeObserver = window.ResizeObserver
    const disconnectMock = vi.fn()
    const observeMock = vi.fn()

    window.ResizeObserver = class MockResizeObserver {
      disconnect = disconnectMock
      observe = observeMock
      unobserve = vi.fn()

      constructor(cb: ResizeObserverCallback) {
        cb(
          [
            {
              contentRect: {
                height: 0,
                width: 800,
              },
            },
          ] as ResizeObserverEntry[],
          this as unknown as ResizeObserver,
        )
      }
    } as unknown as typeof ResizeObserver

    const container = document.createElement("div")
    const containerRef = { current: container }
    const config: ThemeConfig = {
      ...defaultConfig,
      breakpoint: {
        containerRef,
        identifier: "@container",
      },
    }

    const Component: FC = () => {
      const breakpoint = useBreakpoint()

      return <styled.p data-testid="bp">{breakpoint}</styled.p>
    }

    const { unmount } = await render(
      <UIProvider config={config}>
        <Component />
      </UIProvider>,
      { withProvider: false },
    )

    await vi.waitFor(() => {
      expect(observeMock).toHaveBeenCalledWith(container)
    })

    unmount()

    expect(disconnectMock).toHaveBeenCalledWith()

    window.ResizeObserver = defaultResizeObserver
  })

  test("ResizeObserver callback skips when entry is empty", async () => {
    const defaultResizeObserver = window.ResizeObserver
    let capturedCb: ResizeObserverCallback | undefined

    window.ResizeObserver = class MockResizeObserver {
      observe = vi.fn()
      unobserve = vi.fn()
      disconnect = vi.fn()

      constructor(cb: ResizeObserverCallback) {
        capturedCb = cb
      }
    } as unknown as typeof ResizeObserver

    const containerRef = { current: document.createElement("div") }
    const config: ThemeConfig = {
      ...defaultConfig,
      breakpoint: {
        containerRef,
        identifier: "@container",
      },
    }

    const Component: FC = () => {
      const breakpoint = useBreakpoint()

      return <styled.p data-testid="bp">{breakpoint}</styled.p>
    }

    await render(
      <UIProvider config={config}>
        <Component />
      </UIProvider>,
      { withProvider: false },
    )

    const rafSpy = vi.spyOn(window, "requestAnimationFrame")

    capturedCb?.([] as unknown as ResizeObserverEntry[], {} as ResizeObserver)

    expect(rafSpy).not.toHaveBeenCalled()

    rafSpy.mockRestore()
    window.ResizeObserver = defaultResizeObserver
  })
})

"use client"

import type { Breakpoint } from "@yamada-ui/react"
import { useCallback, useMemo, useRef, useSyncExternalStore } from "react"
import {
  useEnvironment,
  useSystem,
  createdDom,
  isUndefined,
  noop,
} from "@yamada-ui/react"

/**
 * `useBreakpoint` is a custom hook that returns the current breakpoint.
 * This hook monitors changes in the window size and returns the appropriate value.
 *
 * @see https://yamada-ui.com/docs/hooks/use-breakpoint
 */
export const useBreakpoint = () => {
  const animationFrameId = useRef(0)
  const { breakpoints, config } = useSystem()
  const { getWindow } = useEnvironment()
  const {
    containerRef,
    direction = "down",
    identifier = "@media screen",
  } = config.breakpoint ?? {}
  const hasContainer = !!containerRef

  const queries = useMemo(() => {
    return breakpoints.queries.map(
      ({ breakpoint, maxW, minMaxQuery, minW }) => {
        const searchValue =
          identifier === "@media screen"
            ? "@media screen and "
            : `${identifier} `
        const query = minMaxQuery?.replace(searchValue, "") ?? ""

        return {
          breakpoint,
          maxW,
          minW,
          query,
        }
      },
    )
  }, [breakpoints, identifier])

  const hasQueries = !!queries.length

  const getBreakpoint = useCallback(
    (width?: number) => {
      if (isUndefined(width)) {
        const win = getWindow()

        if (hasContainer || !hasQueries) return "base"

        for (const { breakpoint, query } of queries) {
          const mql = win?.matchMedia(query)

          if (mql?.matches) return breakpoint
        }
      } else {
        for (const { breakpoint, maxW, minW } of queries) {
          if (direction !== "up") {
            if ((minW ?? 0) <= width) return breakpoint
          } else {
            if (width <= (maxW ?? Infinity)) return breakpoint
          }
        }
      }

      return "base"
    },
    [direction, getWindow, hasContainer, hasQueries, queries],
  )

  const breakpointRef = useRef<Breakpoint>(getBreakpoint())

  const subscribe = useCallback(
    (listener: () => void) => {
      if (!hasContainer || !hasQueries) {
        const observer = queries.map(({ breakpoint, query }): (() => void) => {
          const mql = getWindow()?.matchMedia(query)

          const onChange = (e: MediaQueryListEvent) => {
            if (e.matches) breakpointRef.current = breakpoint

            listener()
          }

          mql?.addEventListener("change", onChange)

          return () => {
            mql?.removeEventListener("change", onChange)
          }
        })

        return () => {
          observer.forEach((unobserve) => unobserve())
        }
      } else if (createdDom()) {
        const observer = new ResizeObserver(([entry]) => {
          if (!entry) return

          cancelAnimationFrame(animationFrameId.current)

          const { width } = entry.contentRect

          breakpointRef.current = getBreakpoint(width)

          animationFrameId.current = requestAnimationFrame(listener)
        })

        if (containerRef.current) observer.observe(containerRef.current)

        return () => {
          observer.disconnect()

          if (process.env.NODE_ENV !== "test")
            cancelAnimationFrame(animationFrameId.current)
        }
      } else {
        return noop
      }
    },
    [containerRef, getBreakpoint, getWindow, hasContainer, hasQueries, queries],
  )

  const getSnapshot = useCallback(() => {
    return breakpointRef.current
  }, [])

  const breakpoint = useSyncExternalStore(subscribe, getSnapshot, getSnapshot)

  return breakpoint
}

import { page, renderHook } from "#test/browser"
import { useUpdateBreakpointEffect } from "./use-update-breakpoint-effect"

describe("useUpdateBreakpointEffect", () => {
  test("Executes callback when breakpoint changes, skipping initial render", async () => {
    await page.viewport(600, 800)

    const callback = vi.fn()

    const { rerender } = await renderHook(() =>
      useUpdateBreakpointEffect(callback, []),
    )

    expect(callback).not.toHaveBeenCalled()

    await page.viewport(900, 800)
    await rerender()

    await vi.waitFor(() => {
      expect(callback).toHaveBeenCalledWith("lg")
    })
  })
})

import type { DependencyList } from "react"
import type { Breakpoint } from "@yamada-ui/react"
import { useUpdateEffect } from "@yamada-ui/react"
import { useBreakpoint } from "./use-breakpoint"

/**
 * `useUpdateBreakpointEffect` is a custom hook that skips the side effect on the initial render and executes a specific callback function when the breakpoint changes.
 *
 * @see https://yamada-ui.com/docs/hooks/use-update-breakpoint-effect
 */
export const useUpdateBreakpointEffect = (
  callback: (breakpoint: Breakpoint) => void,
  deps: DependencyList,
) => {
  const breakpoint = useBreakpoint()

  useUpdateEffect(() => {
    callback(breakpoint)
  }, [breakpoint, ...deps])
}
